import styled from 'styled-components';

export const NavContainer = styled.nav`
display:flex;
justify-content:center;
background-color:#50A6D8;
width:20%;

hr {
    width:60%;
    background:rgb(0,0,0);
}


.links__container {
    list-style:none;
}
a {
    color:rgb(255,255,255);
    text-decoration:none;
}
`
